import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Introducción a Fabric y el desarrollo de Mods","description":"Una breve introducción a Fabric y el desarrollo de mods en Minecraft: Edición de Java.","frontmatter":{"title":"Introducción a Fabric y el desarrollo de Mods","description":"Una breve introducción a Fabric y el desarrollo de mods en Minecraft: Edición de Java.","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"search":false,"files":[]},"headers":[],"relativePath":"es_es/1.20.4/develop/getting-started/introduction-to-fabric-and-modding.md","filePath":"versions/1.20.4/translated/es_es/develop/getting-started/introduction-to-fabric-and-modding.md","lastUpdated":1739538073000}`);var a={name:`es_es/1.20.4/develop/getting-started/introduction-to-fabric-and-modding.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Introducción a Fabric y el desarrollo de Mods <a class="header-anchor" href="#h1" aria-label="Permalink to “Introducción a Fabric y el desarrollo de Mods”">​</a></h1><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to “Requisitos Previos”">​</a></h2><p>Antes de empezar, deberías tener un entendimiento básico de programación en Java, y conocimiento de Programación Orientada a Objetos (POO).</p><p>Si no estás familiarizados con estos conceptos, deberías investigar algunos tutoriales sobre Java y POO antes de que empiezas a desarrollar mods, aquí hay algunos de los recursos que puedes usar para aprender Java y POO:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h3 id="terminologia" tabindex="-1">Terminología <a class="header-anchor" href="#terminologia" aria-label="Permalink to “Terminología”">​</a></h3><p>Antes de empezar, veamos algunos de los términos que usaremos cuando desarrollemos mods para Fabric:</p><ul><li><strong>Mod</strong>: Una modificación al juego, que añade nuevas funciones o características o que cambia funciones o características existentes.</li><li><strong>Mod Loader</strong> (Lanzador o Cargador de Mods): Una herramienta que carga los mods en el juego, como el Lanzador de Fabric.</li><li><strong>Mixin</strong>: Una herramienta para modificar el código del juego durante el tiempo de ejecución - visita <a href="https://fabricmc.net/wiki/tutorial:mixin_introduction" target="_blank" rel="noreferrer">Introducción a los Mixins</a> para más información.</li><li><strong>Gradle</strong>: Una herramienta para la automatización de construcción que se usa para compilar y construir los mods, usado por Fabric para construir mods.</li><li><strong>Mappings</strong> (Mapeos): Un conjunto de mapeos que traducen o &quot;mapean&quot; código ofuscado a código legible.</li><li><strong>Obfuscation</strong> (Ofuscación): El proceso de hacer que el código sea difícil de entender, usando por Mojang para proteger el código de Minecraft.</li><li><strong>Remapping</strong> (Remapeado): El proceso de mapear código ofuscado a código legible.</li></ul><h2 id="¿que-es-fabric" tabindex="-1">¿Qué es Fabric? <a class="header-anchor" href="#¿que-es-fabric" aria-label="Permalink to “¿Qué es Fabric?”">​</a></h2><p>Fabric is un conjunto de herramientas ligeras para moddear Minecraft: Edición de Java.</p><p>Está diseñado para ser una plataforma de moddeado simple y fácil de entender. Fabric es un proyecto dirigido por la comunidad, y es de fuente abierta, lo que significa que cualquiera puede contribuir al proyecto.</p><p>Deberías saber de los cuatro componentes principales de Fabric:</p><ul><li><strong>Fabric Loader</strong> (Lanzador de Fabric): Un lanzador de mods flexible diseñado para Minecraft y otros juegos y aplicaciones, que funciona independiente de la plataforma.</li><li><strong>Fabric Loom</strong>: Un plugin o extensión de Gradle para desarrollar y depurar mods fácilmente.</li><li><strong>Fabric API</strong>: Un conjunto de APIs y herramientas para desarrolladores de mods para ser usadas durante la creación de mods.</li><li><strong>Yarn</strong>: Un conjunto de mapeos de Fabric abiertos. Cualquiera puede usarlos bajo la licencia de Creative Commons Zero.</li></ul><h2 id="¿por-que-es-necesario-fabric-para-crear-mods-para-minecraft" tabindex="-1">¿Por qué es necesario Fabric para crear mods para Minecraft? <a class="header-anchor" href="#¿por-que-es-necesario-fabric-para-crear-mods-para-minecraft" aria-label="Permalink to “¿Por qué es necesario Fabric para crear mods para Minecraft?”">​</a></h2><blockquote><p>El moddeado es el proceso de modificar el juego con el fin de cambiar su comportamiento y añadir nuevas funciones - en el caso de Minecraft, esto puede ser cualquier cosa, como añadir nuevos items, bloques, o entidades, o cambiar las mecánicas del juego o añadiendo nuevos modos de juego.</p></blockquote><p>Minecraft: Edición de Java es ofuscado por Mojang, haciendo que la modificación sea dificil por sí sola. Sin embargo, mediante la ayuda de herramientas para la creación de mods como Fabric, la creación de mods se hace mucho más facil. Hay varios sistemas sde mapeo que pueden asistir en el proceso.</p><p>Loom remappea el código ofuscado a código legible usando estos mappings, permitiéndole a los desarrolladores de mods entender y modificar el código del juego. Yarn es una elección popular y excelente para los mpapings, pero también existen otras opciones. Cada proyecto de mappings tiene sus propias ventajas o enfoque.</p><p>Loom te permite fácilmente desarrollar y compilar mods basados en código remapeado, y el Lanzador de Fabric te permite cargar estos mods en el juego.</p><h2 id="¿que-provee-el-fabric-api-y-por-que-es-necesario" tabindex="-1">¿Qué provee el Fabric API, y por qué es necesario? <a class="header-anchor" href="#¿que-provee-el-fabric-api-y-por-que-es-necesario" aria-label="Permalink to “¿Qué provee el Fabric API, y por qué es necesario?”">​</a></h2><blockquote><p>El Fabric API es un conjunto de APIs y herramientas para desarrolladores de mods para ser usadas durante la creación de mods.</p></blockquote><p>Fabric API provee un conjunto amplio de APIs basadas en la funcionalidad de Minecraft existente - por ejemplo, provee nuevos ganchos y eventos para ser usados por desarrolladores de mods, o provee nuevas utilidades para facilitar el desarrollo de mods - como <em>access wideners</em> (ampliadores de acceso) transitivos y la abilidad de usar registros internos, como el registro de items compostables.</p><p>Mientras que Fabric API ofrece funciones poderosas, algunas tares, como la registración básica de bloques, puede ser lograda sin ella, usando los APIs vanilla.</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};